### 2. JOIN Query Generation
\`\`\`rust
impl<T: Model> SelectBuilder<T> {
    /// Configure eager loading for this query.
    pub fn eager(mut self, loader: EagerLoader<T>) -> Self {
        self.eager_loader = Some(loader);
        self
    }

    /// Build SQL with JOINs for eager loading.
    fn build_eager_sql(&self) -> (String, Vec<Value>) {
        let mut sql = format!("SELECT {} FROM {}", 
            self.build_eager_columns(),
            T::TABLE_NAME
        );

        // Add JOINs for each included relationship
        for include in &self.eager_loader.as_ref().unwrap().includes {
            let rel = T::relationship_by_name(include.relationship)
                .expect("Unknown relationship");

            sql.push_str(&self.build_join_clause(rel));
        }

        // Add WHERE, ORDER BY, etc.
        // ...

        (sql, params)
    }

    fn build_join_clause(&self, rel: &RelationshipInfo) -> String {
        match rel.kind {
            RelationshipKind::ManyToOne | RelationshipKind::OneToOne => {
                // LEFT JOIN related_table ON local.fk = related.pk
                format!(
                    " LEFT JOIN {} ON {}.{} = {}.{}",
                    rel.related_table,
                    T::TABLE_NAME,
                    rel.local_key.unwrap(),
                    rel.related_table,
                    "id" // TODO: Get actual PK column
                )
            }
            RelationshipKind::OneToMany => {
                // LEFT JOIN related_table ON related.fk = local.pk
                format!(
                    " LEFT JOIN {} ON {}.{} = {}.{}",
                    rel.related_table,
                    rel.related_table,
                    rel.remote_key.unwrap(),
                    T::TABLE_NAME,
                    "id" // TODO: Get actual PK column
                )
            }
            RelationshipKind::ManyToMany => {
                // LEFT JOIN link_table ON local.pk = link.local_col
                // LEFT JOIN related_table ON link.remote_col = related.pk
                let link = rel.link_table.as_ref().unwrap();
                format!(
                    " LEFT JOIN {} ON {}.id = {}.{} LEFT JOIN {} ON {}.{} = {}.id",
                    link.table_name,
                    T::TABLE_NAME,
                    link.table_name,
                    link.local_column,
                    rel.related_table,
                    link.table_name,
                    link.remote_column,
                    rel.related_table
                )
            }
        }
    }

    fn build_eager_columns(&self) -> String {
        let mut columns = Vec::new();

        // Parent columns with alias prefix
        for field in T::fields() {
            columns.push(format!("{}.{} AS {}__{}", 
                T::TABLE_NAME, 
                field.column_name,
                T::TABLE_NAME,
                field.column_name
            ));
        }

        // Related columns for each include
        // ...

        columns.join(", ")
    }
}
