### 3. Result Hydration
\`\`\`rust
impl<T: Model> SelectBuilder<T> {
    /// Execute query and hydrate results with eager-loaded relationships.
    pub async fn all_eager(self, conn: &impl Connection) -> Result<Vec<T>> {
        let (sql, params) = self.build_eager_sql();
        let rows = conn.fetch_all(&sql, &params).await?;

        self.hydrate_results(rows)
    }

    fn hydrate_results(&self, rows: Vec<Row>) -> Result<Vec<T>> {
        let mut results: HashMap<Value, T> = HashMap::new();

        for row in rows {
            // Extract parent object
            let parent_pk = row.get_prefixed(T::TABLE_NAME, "id")?;

            let parent = results.entry(parent_pk.clone())
                .or_insert_with(|| T::from_prefixed_row(&row, T::TABLE_NAME).unwrap());

            // Extract and attach related objects
            for include in &self.eager_loader.as_ref().unwrap().includes {
                let rel = T::relationship_by_name(include.relationship).unwrap();
                self.hydrate_relationship(parent, rel, &row)?;
            }
        }

        Ok(results.into_values().collect())
    }
}
