/// E2E: Eager vs lazy comparison
#[tokio::test]
async fn e2e_eager_vs_lazy_performance() {
    // Load 100 heroes

    // Method 1: Lazy (N+1 queries)
    let start_lazy = std::time::Instant::now();
    let heroes_lazy = session.query::<Hero>().all().await.unwrap();
    for hero in &mut heroes_lazy {
        hero.team.load(&mut session).await.unwrap();
    }
    let lazy_time = start_lazy.elapsed();

    // Method 2: Eager (1 query)
    let start_eager = std::time::Instant::now();
    let heroes_eager = select!(Hero)
        .eager(EagerLoader::new().include("team"))
        .all_eager(&conn)
        .await
        .unwrap();
    let eager_time = start_eager.elapsed();

    tracing::info!(
        lazy_ms = lazy_time.as_millis(),
        eager_ms = eager_time.as_millis(),
        "Eager loading is {}x faster",
        lazy_time.as_millis() / eager_time.as_millis().max(1)
    );

    assert!(eager_time < lazy_time, "Eager should be faster");
}
